def parse_nombre_latam(raw: str) -> dict:
    toks = raw.strip().split()
    if len(toks) < 3:
        return {"status": "review", "raw": raw, "tokens": toks}
    return {
        "status": "ok",
        "raw": raw,
        "nombres": " ".join(toks[:-2]),
        "apellidos": " ".join(toks[-2:]),
    }

print(parse_nombre_latam("Ana"))
print(parse_nombre_latam("Ana María Quispe Huamán"))

