def normalize_email(raw: str):
    s = raw.strip().casefold()
    if s.count("@") != 1 or " " in s:
        return {"status": "review_error", "value": None, "raw": raw}
    local, domain = s.split("@")
    if not local or not domain:
        return {"status": "review_error", "value": None, "raw": raw}
    return {"status": "ok", "value": s, "raw": raw}

for e in ["  A@B.COM ", "a b@c.com", "@nodomain", "user+tag@example.com"]:
    print(e, "→", normalize_email(e))

